class SetMeshNormal(NodeBuilder):
    """
    Store a normal vector for each mesh element

    Parameters
    ----------
    mesh : InputGeometry
        Mesh
    remove_custom : InputBoolean
        Remove Custom
    edge_sharpness : InputBoolean
        Edge Sharpness
    face_sharpness : InputBoolean
        Face Sharpness
    custom_normal : InputVector
        Custom Normal

    Outputs
    -------
    mesh : GeometrySocket
        Mesh
    """

    _bl_idname = "GeometryNodeSetMeshNormal"
    node: bpy.types.GeometryNodeSetMeshNormal

    class Inputs(SocketAccessor):
        mesh: Socket
        remove_custom: Socket
        edge_sharpness: Socket
        face_sharpness: Socket
        custom_normal: Socket

    class Outputs(SocketAccessor):
        mesh: GeometrySocket

    @property
    def i(self) -> "SetMeshNormal.Inputs":
        return SetMeshNormal.Inputs(self.node.inputs, "input")

    @property
    def o(self) -> "SetMeshNormal.Outputs":
        return SetMeshNormal.Outputs(self.node.outputs, "output")

    def __init__(
        self,
        mesh: InputGeometry = None,
        remove_custom: InputBoolean = True,
        edge_sharpness: InputBoolean = False,
        face_sharpness: InputBoolean = False,
        custom_normal: InputVector = None,
        *,
        mode: Literal["SHARPNESS", "FREE", "TANGENT_SPACE"] = "SHARPNESS",
        domain: Literal["POINT", "FACE", "CORNER"] = "POINT",
    ):
        super().__init__()
        self.mode = mode
        self.domain = domain
        _all_args = {
            "Mesh": mesh,
            "Remove Custom": remove_custom,
            "Edge Sharpness": edge_sharpness,
            "Face Sharpness": face_sharpness,
            "Custom Normal": custom_normal,
        }
        _socket_ids = {s.identifier for s in self.node.inputs}
        key_args = {k: v for k, v in _all_args.items() if k in _socket_ids}
        self._establish_links(**key_args)

    @classmethod
    def sharpness(
        cls,
        mesh: InputGeometry = None,
        remove_custom: InputBoolean = True,
        edge_sharpness: InputBoolean = False,
        face_sharpness: InputBoolean = False,
    ) -> "SetMeshNormal":
        """Create Set Mesh Normal with operation 'Sharpness'. Store the sharpness of each face or edge. Similar to the "Shade Smooth" and "Shade Flat" operators."""
        return cls(
            mode="SHARPNESS",
            mesh=mesh,
            remove_custom=remove_custom,
            edge_sharpness=edge_sharpness,
            face_sharpness=face_sharpness,
        )

    @classmethod
    def free(
        cls, mesh: InputGeometry = None, custom_normal: InputVector = None
    ) -> "SetMeshNormal":
        """Create Set Mesh Normal with operation 'Free'. Store custom normals as simple vectors in the local space of the mesh. Values are not necessarily updated automatically later on as the mesh is deformed."""
        return cls(mode="FREE", mesh=mesh, custom_normal=custom_normal)

    @classmethod
    def tangent_space(
        cls, mesh: InputGeometry = None, custom_normal: InputVector = None
    ) -> "SetMeshNormal":
        """Create Set Mesh Normal with operation 'Tangent Space'. Store normals in a deformation dependent custom transformation space. This method is slower, but can be better when subsequent operations change the mesh without handling normals specifically."""
        return cls(mode="TANGENT_SPACE", mesh=mesh, custom_normal=custom_normal)

    @classmethod
    def point(
        cls,
        mesh: InputGeometry = None,
        remove_custom: InputBoolean = True,
        edge_sharpness: InputBoolean = False,
        face_sharpness: InputBoolean = False,
    ) -> "SetMeshNormal":
        """Create Set Mesh Normal with operation 'Point'. Attribute on point"""
        return cls(
            domain="POINT",
            mesh=mesh,
            remove_custom=remove_custom,
            edge_sharpness=edge_sharpness,
            face_sharpness=face_sharpness,
        )

    @classmethod
    def face(
        cls,
        mesh: InputGeometry = None,
        remove_custom: InputBoolean = True,
        edge_sharpness: InputBoolean = False,
        face_sharpness: InputBoolean = False,
    ) -> "SetMeshNormal":
        """Create Set Mesh Normal with operation 'Face'. Attribute on mesh faces"""
        return cls(
            domain="FACE",
            mesh=mesh,
            remove_custom=remove_custom,
            edge_sharpness=edge_sharpness,
            face_sharpness=face_sharpness,
        )

    @classmethod
    def face_corner(
        cls,
        mesh: InputGeometry = None,
        remove_custom: InputBoolean = True,
        edge_sharpness: InputBoolean = False,
        face_sharpness: InputBoolean = False,
    ) -> "SetMeshNormal":
        """Create Set Mesh Normal with operation 'Face Corner'. Attribute on mesh face corner"""
        return cls(
            domain="CORNER",
            mesh=mesh,
            remove_custom=remove_custom,
            edge_sharpness=edge_sharpness,
            face_sharpness=face_sharpness,
        )

    @property
    def mode(self) -> Literal["SHARPNESS", "FREE", "TANGENT_SPACE"]:
        return self.node.mode

    @mode.setter
    def mode(self, value: Literal["SHARPNESS", "FREE", "TANGENT_SPACE"]):
        self.node.mode = value

    @property
    def domain(self) -> Literal["POINT", "FACE", "CORNER"]:
        return self.node.domain

    @domain.setter
    def domain(self, value: Literal["POINT", "FACE", "CORNER"]):
        self.node.domain = value


